INSERT INTO public.exercises (external_id,name,muscle_group,secondary_muscles,equipment,category,instructions,description,image_url,source,is_public) VALUES ('Overhead_Lat','Overhead Lat','dorsales',ARRAY['tríceps'],'otro','stretching',ARRAY['Sit upright on the floor with your partner behind you. Raise one arm straight up, and flex the elbow, attempting to touch your hand to your back. Your parner should hold your tricep and wrist. This will be your starting position.','Attempt to pull your upper arm to your side as your partner prevents you from doing actually doing so.','After 10-20 seconds, relax the arm and allow your partner to further stretch the lat by applying gentle pressure to the tricep. Hold for 10-20 seconds, and then switch sides.'],'Sit upright on the floor with your partner behind you. Raise one arm straight up, and flex the elbow, attempting to touch your hand to your back. Your parner should hold your tricep and wrist. This will be your starting position. Attempt to pull your upper arm to your side as your partner prevents you from doing actually doing so. After 10-20 seconds, relax the arm and allow your partner to further stretch the lat by applying gentle pressure to the tricep. Hold for 10-20 seconds, and then switch sides.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Overhead_Lat/0.jpg','exercisedb',true),('Overhead_Slam','Overhead Slam','dorsales',ARRAY[]::text[],'balón medicinal','plyometrics',ARRAY['Hold a medine ball with both hands and stand with your feet at shoulder width. This will be your starting position.','Initiate the countermovement by raising the ball above your head and fully extending your body.','Reverse the motion, slamming the ball into the ground directly in front of you as hard as you can.','Receive the ball with both hands on the bounce and repeat the movement.'],'Hold a medine ball with both hands and stand with your feet at shoulder width. This will be your starting position. Initiate the countermovement by raising the ball above your head and fully extending your body. Reverse the motion, slamming the ball into the ground directly in front of you as hard as you can. Receive the ball with both hands on the bounce and repeat the movement.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Overhead_Slam/0.jpg','exercisedb',true),('Overhead_Squat','Overhead Squat','cuádriceps',ARRAY['abdominales','pantorrillas','glúteos','isquiotibiales','espalda baja','hombros','tríceps'],'barra','olympic weightlifting',ARRAY['Start out by having a barbell in front of you on the floor. Your feet should be wider than shoulder width apart from each other.','Bend the knees and use a pronated grip (palms facing you) to grab the barbell. Your hands should be at a wider than shoulder width apart from each other before lifting. Once you are positioned, lift the barbell up until you can rest it on your chest.','Move the barbell over and slightly behind your head and make sure your arms are fully extended. Keep your head up at all times and also maintain a straight back. Retract your shoulder blades. This is your starting position.','Slowly lower the weight by bending your knees until your thighs are parallel to the ground while inhaling. Tip: Keep your back straight while performing this exercise to avoid any injuries and your arms should remain extended and over your head at all times.','Now use your feet and legs to help bring the weight back up to the starting position while exhaling.','Repeat for the recommended amount of repetitions.'],'Start out by having a barbell in front of you on the floor. Your feet should be wider than shoulder width apart from each other. Bend the knees and use a pronated grip (palms facing you) to grab the barbell. Your hands should be at a wider than shoulder width apart from each other before lifting. Once you are positioned, lift the barbell up until you can rest it on your chest. Move the barbell over and slightly behind your head and make sure your arms are fully extended. Keep your head up at all times and also maintain a straight back. Retract your shoulder blades. This is your starting position. Slowly lower the weight by bending your knees until your thighs are parallel to the ground while inhaling. Tip: Keep your back straight while performing this exercise to avoid any injuries and your arms should remain extended and over your head at all times. Now use your feet and legs to help bring the weight back up to the starting position while exhaling. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Overhead_Squat/0.jpg','exercisedb',true),('Overhead_Stretch','Overhead Stretch','abdominales',ARRAY['pecho','antebrazos','dorsales','tríceps'],NULL,'stretching',ARRAY['Standing straight up, lace your fingers together and open your palms to the ceiling. Keep your shoulders down as you extend your arms up.','To create a full torso stretch, pull your tailbone down and stabilize your torso as you do this. Stretch the muscles on both the front and the back of the torso.'],'Standing straight up, lace your fingers together and open your palms to the ceiling. Keep your shoulders down as you extend your arms up. To create a full torso stretch, pull your tailbone down and stabilize your torso as you do this. Stretch the muscles on both the front and the back of the torso.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Overhead_Stretch/0.jpg','exercisedb',true),('Overhead_Triceps','Overhead Triceps','tríceps',ARRAY['dorsales'],'peso corporal','stretching',ARRAY['Sit upright on the floor with your partner behind you. Raise one arm straight up, and flex the elbow, attempting to touch your hand to your back. Your parner should hold your elbow and wrist. This will be your starting position.','Attempt to extend the arm straight into the air as your partner prevents you from doing actually doing so.','After 10-20 seconds, relax the arm and allow your partner to further stretch the tricep by applying gentle pressure to the wrist. Hold for 10-20 seconds, and then switch sides.'],'Sit upright on the floor with your partner behind you. Raise one arm straight up, and flex the elbow, attempting to touch your hand to your back. Your parner should hold your elbow and wrist. This will be your starting position. Attempt to extend the arm straight into the air as your partner prevents you from doing actually doing so. After 10-20 seconds, relax the arm and allow your partner to further stretch the tricep by applying gentle pressure to the wrist. Hold for 10-20 seconds, and then switch sides.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Overhead_Triceps/0.jpg','exercisedb',true),('Pallof_Press','Pallof Press','abdominales',ARRAY['pecho','hombros','tríceps'],'cable','strength',ARRAY['Connect a standard handle to a tower, and—if possible—position the cable to shoulder height. If not, a low pulley will suffice.','With your side to the cable, grab the handle with both hands and step away from the tower. You should be approximately arm''''s length away from the pulley, with the tension of the weight on the cable.','With your feet positioned hip-width apart and knees slightly bent, hold the cable to the middle of your chest. This will be your starting position.','Press the cable away from your chest, fully extending both arms. You core should be tight and engaged.','Hold the repetition for several seconds before returning to the starting position.','At the conclusion of the set, repeat facing the other direction.'],'Connect a standard handle to a tower, and—if possible—position the cable to shoulder height. If not, a low pulley will suffice. With your side to the cable, grab the handle with both hands and step away from the tower. You should be approximately arm''s length away from the pulley, with the tension of the weight on the cable. With your feet positioned hip-width apart and knees slightly bent, hold the cable to the middle of your chest. This will be your starting position. Press the cable away from your chest, fully extending both arms. You core should be tight and engaged. Hold the repetition for several seconds before returning to the starting position. At the conclusion of the set, repeat facing the other direction.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pallof_Press/0.jpg','exercisedb',true),('Pallof_Press_With_Rotation','Pallof Press With Rotation','abdominales',ARRAY['pecho','hombros','tríceps'],'cable','strength',ARRAY['Connect a standard handle to a tower, and position the cable to shoulder height.','With your side to the cable, grab the handle with one hand and step away from the tower. You should be approximately arm''''s length away from the pulley, with the tension of the weight on the cable. Align outstretched arm with cable.','With your feet positioned hip-width apart, pull the cable into your chest and grab the handle with your other hand. Both hands should be on the handle at this time.','Facing forward, press the cable away from your chest. You core should be tight and engaged.','Keeping your hips straight, twist your torso away from the pulley until you get a full quarter rotation.','Maintain your rigid stance and straight arms. Return to the neutral position in a slow and controlled manner. Your arms should be extended in front of you.','With the side tension still engaging your core, bring your hands to your chest and immediately press outward to a fully extended position. This constitutes one rep.','Repeat to failure.','Then, reposition and repeat the same series of movements on the opposite side.'],'Connect a standard handle to a tower, and position the cable to shoulder height. With your side to the cable, grab the handle with one hand and step away from the tower. You should be approximately arm''s length away from the pulley, with the tension of the weight on the cable. Align outstretched arm with cable. With your feet positioned hip-width apart, pull the cable into your chest and grab the handle with your other hand. Both hands should be on the handle at this time. Facing forward, press the cable away from your chest. You core should be tight and engaged. Keeping your hips straight, twist your torso away from the pulley until you get a full quarter rotation. Maintain your rigid stance and straight arms. Return to the neutral position in a slow and controlled manner. Your arms should be extended in front of you. With the side tension still engaging your core, bring your hands to your chest and immediately press outward to a fully extended position. This constitutes one rep. Repeat to failure. Then, reposition and repeat the same series of movements on the opposite side.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pallof_Press_With_Rotation/0.jpg','exercisedb',true),('Palms-Down_Dumbbell_Wrist_Curl_Over_A_Bench','Palms-Down Dumbbell Wrist Curl Over A Bench','antebrazos',ARRAY[]::text[],'mancuernas','strength',ARRAY['Start out by placing two dumbbells on one side of a flat bench.','Kneel down on both of your knees so that your body is facing the flat bench.','Use your arms to grab both of the dumbbells with a pronated grip (palms facing down) and bring them up so that your forearms are resting against the flat bench. Your wrists should be hanging over the edge.','Start out by curling your wrist upwards and exhaling.','Slowly lower your wrists back down to the starting position while inhaling.','Your forearms should be stationary as your wrist is the only movement needed to perform this exercise.','Repeat for the recommended amount of repetitions.'],'Start out by placing two dumbbells on one side of a flat bench. Kneel down on both of your knees so that your body is facing the flat bench. Use your arms to grab both of the dumbbells with a pronated grip (palms facing down) and bring them up so that your forearms are resting against the flat bench. Your wrists should be hanging over the edge. Start out by curling your wrist upwards and exhaling. Slowly lower your wrists back down to the starting position while inhaling. Your forearms should be stationary as your wrist is the only movement needed to perform this exercise. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Palms-Down_Dumbbell_Wrist_Curl_Over_A_Bench/0.jpg','exercisedb',true),('Palms-Down_Wrist_Curl_Over_A_Bench','Palms-Down Wrist Curl Over A Bench','antebrazos',ARRAY[]::text[],'barra','strength',ARRAY['Start out by placing a barbell on one side of a flat bench.','Kneel down on both of your knees so that your body is facing the flat bench.','Use your arms to grab the barbell with a pronated grip (palms down) and bring them up so that your forearms are resting against the flat bench. Your wrists should be hanging over the edge.','Start out by curling your wrist upwards and exhaling.','Slowly lower your wrists back down to the starting position while inhaling.','Your forearms should be stationary as your wrist is the only movement needed to perform this exercise.','Repeat for the recommended amount of repetitions.'],'Start out by placing a barbell on one side of a flat bench. Kneel down on both of your knees so that your body is facing the flat bench. Use your arms to grab the barbell with a pronated grip (palms down) and bring them up so that your forearms are resting against the flat bench. Your wrists should be hanging over the edge. Start out by curling your wrist upwards and exhaling. Slowly lower your wrists back down to the starting position while inhaling. Your forearms should be stationary as your wrist is the only movement needed to perform this exercise. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Palms-Down_Wrist_Curl_Over_A_Bench/0.jpg','exercisedb',true),('Palms-Up_Barbell_Wrist_Curl_Over_A_Bench','Palms-Up Barbell Wrist Curl Over A Bench','antebrazos',ARRAY[]::text[],'barra','strength',ARRAY['Start out by placing a barbell on one side of a flat bench.','Kneel down on both of your knees so that your body is facing the flat bench.','Use your arms to grab the barbell with a supinated grip (palms up) and bring them up so that your forearms are resting against the flat bench. Your wrists should be hanging over the edge.','Start out by curling your wrist upwards and exhaling.','Slowly lower your wrists back down to the starting position while inhaling.','Your forearms should be stationary as your wrist is the only movement needed to perform this exercise.','Repeat for the recommended amount of repetitions.'],'Start out by placing a barbell on one side of a flat bench. Kneel down on both of your knees so that your body is facing the flat bench. Use your arms to grab the barbell with a supinated grip (palms up) and bring them up so that your forearms are resting against the flat bench. Your wrists should be hanging over the edge. Start out by curling your wrist upwards and exhaling. Slowly lower your wrists back down to the starting position while inhaling. Your forearms should be stationary as your wrist is the only movement needed to perform this exercise. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Palms-Up_Barbell_Wrist_Curl_Over_A_Bench/0.jpg','exercisedb',true);